  eval_preserves_synthetic_direct_call_ready_summary_call_package_statement ->
  eval_preserves_synthetic_direct_call_ready_summary_exact_call_package_statement.
Proof.
  intros Hpackage. split.
  - eapply eval_preserves_typing_roots_synthetic_direct_call_ready_summary_prefix_exact_call_statement_of_prefix.
    exact (eval_preserves_synthetic_direct_call_ready_summary_call_package_prefix
      Hpackage).
  - eapply eval_preserves_frame_param_scope_synthetic_direct_call_ready_summary_exact_call_statement_of_prefix.
    exact (eval_preserves_synthetic_direct_call_ready_summary_call_package_scope
      Hpackage).
Qed.

Lemma eval_args_preserves_root_names_keys_ready_prefix_ctx :
  eval_preserves_typing_roots_ready_prefix_mutual_statement ->
  forall env s args s_args vs
      (Ω : outlives_ctx) (n : nat) R Σ ps Σ_args R_args arg_roots,
    eval_args env s args s_args vs ->
    provenance_ready_args args ->
    store_typed_prefix env s Σ ->
    store_roots_within R s ->
    store_no_shadow s ->
    root_env_no_shadow R ->
    root_env_ctx_roots_named R Σ ->
    root_env_ctx_keys_named R Σ ->
    typed_args_roots env Ω n R Σ args ps Σ_args R_args arg_roots ->
    Forall (fun roots => root_set_store_roots_named roots s_args) arg_roots /\
    root_env_store_keys_named R_args s_args.
Proof.
  intros Hprefix_ready env s args s_args vs Ω n R Σ ps Σ_args R_args
    arg_roots Heval_args Hready_args Hstore Hroots Hshadow Hrn Hctx_roots
    Hctx_keys Htyped_args.
  destruct (proj1 (proj2 Hprefix_ready)
              env s args s_args vs Heval_args Ω n R Σ ps Σ_args R_args
              arg_roots Hready_args Hstore Hroots Hshadow Hrn Htyped_args)
    as [Hstore_args _].
  destruct (proj1 (proj2 (typed_roots_ctx_roots_named_mutual env Ω n))
              R Σ args ps Σ_args R_args arg_roots Htyped_args Hrn
              Hctx_roots)
    as [_ Harg_roots_ctx_named].
  pose proof (proj1 (proj2 (typed_roots_ctx_keys_named_mutual env Ω n))
                R Σ args ps Σ_args R_args arg_roots Htyped_args Hrn
                Hctx_keys) as Hctx_keys_args.
  split.
  - clear Htyped_args.
    induction Harg_roots_ctx_named as [| roots_i rest Hctx_named_i _ IH].
    + constructor.
    + constructor.
      * eapply root_set_ctx_roots_named_store_typed_prefix; eassumption.
      * exact IH.
  - eapply root_env_ctx_keys_named_store_typed_prefix; eassumption.
Qed.

Lemma eval_args_preserves_root_names_keys_ready_prefix_ctx_full :
  eval_preserves_typing_roots_ready_prefix_mutual_statement ->
  forall env s args s_args vs
      (Ω : outlives_ctx) (n : nat) R Σ ps Σ_args R_args arg_roots,
    eval_args env s args s_args vs ->
    provenance_ready_args args ->
    store_typed_prefix env s Σ ->
    store_roots_within R s ->
    store_no_shadow s ->
    root_env_no_shadow R ->
    root_env_ctx_roots_named R Σ ->
    root_env_ctx_keys_named R Σ ->
    typed_args_roots env Ω n R Σ args ps Σ_args R_args arg_roots ->
    root_env_store_roots_named R_args s_args /\
    Forall (fun roots => root_set_store_roots_named roots s_args) arg_roots /\
    root_env_store_keys_named R_args s_args.
Proof.
  intros Hprefix_ready env s args s_args vs Ω n R Σ ps Σ_args R_args
    arg_roots Heval_args Hready_args Hstore Hroots Hshadow Hrn Hctx_roots
    Hctx_keys Htyped_args.
  destruct (proj1 (proj2 Hprefix_ready)
              env s args s_args vs Heval_args Ω n R Σ ps Σ_args R_args
              arg_roots Hready_args Hstore Hroots Hshadow Hrn Htyped_args)
    as [Hstore_args _].
  destruct (proj1 (proj2 (typed_roots_ctx_roots_named_mutual env Ω n))
              R Σ args ps Σ_args R_args arg_roots Htyped_args Hrn
              Hctx_roots)
    as [Hargs_ctx_roots Harg_roots_ctx_named].
  pose proof (proj1 (proj2 (typed_roots_ctx_keys_named_mutual env Ω n))
                R Σ args ps Σ_args R_args arg_roots Htyped_args Hrn
                Hctx_keys) as Hctx_keys_args.
  repeat split.
  - eapply root_env_ctx_roots_named_store_typed_prefix; eassumption.
  - eapply Forall_impl; [| exact Harg_roots_ctx_named].
    intros roots_i Hctx_named_i.
    eapply root_set_ctx_roots_named_store_typed_prefix; eassumption.
  - eapply root_env_ctx_keys_named_store_typed_prefix; eassumption.
Qed.


Lemma store_typed_prefix_ctx_names_in_store_names :
  forall env s Σ x,
    store_typed_prefix env s Σ ->
    In x (ctx_names Σ) ->
    In x (store_names s).
Proof.
  intros env s Σ x Hstore Hin.
  unfold store_typed_prefix in Hstore.
  destruct Hstore as [entries [frame [Hs Htyped]]].
  subst s.
  induction Htyped as [| se ce entries_tail Σ_tail Hentry Htyped IH]; simpl in *.
  - contradiction.
  - destruct ce as [[[cx cT] cst] cm].
    destruct se as [sx sT sv sst].
    simpl in *.
    destruct Hentry as [Heq _].
    destruct Hin as [Hin | Hin].
    + subst x. left. exact Heq.
    + right. exact (IH Hin).
Qed.

Lemma typed_env_roots_preserves_ctx_names_in_store_prefix :
  forall env s Ω n R Σ e T Σ' R' roots,
    preservation_ready_expr e ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ e T Σ' R' roots ->
    forall x, In x (ctx_names Σ') -> In x (store_names s).
Proof.
  intros env s Ω n R Σ e T Σ' R' roots _Hready Hstore Htyped x Hin.
  pose proof (typed_env_roots_structural env Ω n R Σ e T Σ' R' roots
    Htyped) as Hstruct.
  pose proof (typed_env_structural_same_bindings env Ω n Σ e T Σ'
    Hstruct) as Hsame.
  rewrite (sctx_same_bindings_names_alpha Σ Σ' Hsame) in Hin.
  eapply store_typed_prefix_ctx_names_in_store_names; eassumption.
Qed.

Lemma root_env_ctx_roots_named_store_names_subset_direct_route :
  forall R Σ s,
    (forall x, In x (ctx_names Σ) -> In x (store_names s)) ->
    root_env_ctx_roots_named R Σ ->
    root_env_store_roots_named R s.
Proof.
  unfold root_env_ctx_roots_named, root_env_store_roots_named.
  intros R Σ s Hsubset Hctx x roots z Hlookup Hin.
  apply Hsubset. eapply Hctx; eassumption.
Qed.

Lemma root_set_ctx_roots_named_store_names_subset_direct_route :
  forall roots Σ s,
    (forall x, In x (ctx_names Σ) -> In x (store_names s)) ->
    root_set_ctx_roots_named roots Σ ->
    root_set_store_roots_named roots s.
Proof.
  unfold root_set_ctx_roots_named, root_set_store_roots_named.
  intros roots Σ s Hsubset Hctx z Hin.
  apply Hsubset. apply Hctx. exact Hin.
Qed.

Lemma root_env_ctx_keys_named_store_names_subset_direct_route :
  forall R Σ s,
    (forall x, In x (ctx_names Σ) -> In x (store_names s)) ->
    root_env_ctx_keys_named R Σ ->
    root_env_store_keys_named R s.
Proof.
  unfold root_env_ctx_keys_named, root_env_store_keys_named.
  intros R Σ s Hsubset Hkeys.
  eapply root_env_keys_named_weaken.
  - exact Hkeys.
  - exact Hsubset.
Qed.

Lemma store_roots_within_update_env_union_same_direct_route :
  forall R s x roots_old roots_new,
    store_roots_within R s ->
    root_env_lookup x R = Some roots_old ->
    store_roots_within
      (root_env_update x (root_set_union roots_old roots_new) R) s.
Proof.
  intros R s x roots_old roots_new Hwithin Hlookup_x.
  induction Hwithin as [R | R se rest Hentry Hrest IH].
  - constructor.
  - inversion Hentry as [R0 sx sT sv sst roots Hlookup_se Hvalue_se];
      subst R0 se.
    constructor.
    + destruct (ident_eqb x sx) eqn:Heq.
      * apply ident_eqb_eq in Heq. subst sx.
        rewrite Hlookup_x in Hlookup_se. inversion Hlookup_se; subst roots.
        eapply SERW_Entry.
        -- eapply root_env_lookup_update_eq. exact Hlookup_x.
        -- apply value_roots_within_union_l. exact Hvalue_se.
      * eapply SERW_Entry.
        -- rewrite root_env_lookup_update_neq.
           ++ exact Hlookup_se.
           ++ intros Hsame. subst sx.
              rewrite ident_eqb_refl in Heq. discriminate.
        -- exact Hvalue_se.
    + apply IH. exact Hlookup_x.
Qed.

Lemma typed_env_roots_store_roots_within_update_result_direct_route :
  forall env s Ω n R Σ e_new T_new Σ1 R1 roots_new x roots_old,
    typed_env_roots env Ω n R Σ e_new T_new Σ1 R1 roots_new ->
    store_roots_within R1 s ->
    root_env_lookup x R1 = Some roots_old ->
    store_roots_within
      (root_env_update x (root_set_union roots_old roots_new) R1) s.
Proof.
  intros env s Ω n R Σ e_new T_new Σ1 R1 roots_new x roots_old
    _Htyped Hwithin Hlookup.
  eapply store_roots_within_update_env_union_same_direct_route; eassumption.
Qed.

Lemma typed_env_roots_preserves_store_root_names_keys_prefix :
  forall env s Ω n R Σ e T Σ' R' roots,
    preservation_ready_expr e ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ e T Σ' R' roots ->
    root_env_no_shadow R ->
    root_env_ctx_roots_named R Σ ->
    root_env_ctx_keys_named R Σ ->
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros env s Ω n R Σ e T Σ' R' roots Hready Hstore Htyped Hrn
    Hctx_roots Hctx_keys.
  destruct (proj1 (typed_roots_ctx_roots_named_mutual env Ω n)
              R Σ e T Σ' R' roots Htyped Hrn Hctx_roots)
    as [Hctx_roots' Hroots_ctx].
  pose proof (proj1 (typed_roots_ctx_keys_named_mutual env Ω n)
                R Σ e T Σ' R' roots Htyped Hrn Hctx_keys)
    as Hctx_keys'.
  assert (Hsubset : forall x, In x (ctx_names Σ') -> In x (store_names s)).
  { intros x Hin.
    eapply typed_env_roots_preserves_ctx_names_in_store_prefix;
      eassumption. }
  repeat split.
  - eapply root_env_ctx_roots_named_store_names_subset_direct_route;
      eassumption.
  - eapply root_set_ctx_roots_named_store_names_subset_direct_route;
      eassumption.
  - eapply root_env_ctx_keys_named_store_names_subset_direct_route;
      eassumption.
Qed.

Definition preservation_ready_expr_static_runtime_named_statement : Prop :=
  forall env s e (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_expr e ->
    typed_env_roots env Ω n R Σ e T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.

Definition preservation_ready_expr_static_runtime_named_prefix_statement : Prop :=
  forall env s e (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_expr e ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ e T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.

Lemma preservation_ready_expr_static_runtime_named_prefix_of_static :
  preservation_ready_expr_static_runtime_named_statement ->
  preservation_ready_expr_static_runtime_named_prefix_statement.
Proof.
  intros Hstatic env s e Ω n R Σ T Σ' R' roots Hready _Hstore Htyped
    Hrn Hwithin Hnamed Hkeys.
  eapply Hstatic; eassumption.
Qed.

Lemma root_env_lookup_store_roots_named_direct_route :
  forall R s x roots,
    root_env_store_roots_named R s ->
    root_env_lookup x R = Some roots ->
    root_set_store_roots_named roots s.
Proof.
  unfold root_env_store_roots_named, root_set_store_roots_named.
  intros R s x roots Hnamed Hlookup z Hin.
  eapply Hnamed; eassumption.
Qed.

Lemma root_set_store_roots_named_single_of_store_roots_within_direct_route :
  forall R s x,
    store_roots_within R s ->
    In x (store_names s) ->
    root_set_store_roots_named [RStore x] s.
Proof.
  intros R s x Hwithin Hin.
  destruct (store_roots_within_name_lookup_some R s x Hwithin Hin) as [_ _].
  apply root_set_store_roots_named_single. exact Hin.
Qed.

Lemma root_of_place_store_roots_named_direct_route :
  forall s p x path,
    In x (store_names s) ->
    place_path p = Some (x, path) ->
    root_set_store_roots_named (root_of_place p) s.
Proof.
  intros s p x path Hin Hpath.
  unfold root_of_place. rewrite Hpath.
  apply root_set_store_roots_named_single. exact Hin.
Qed.

Lemma root_of_place_store_roots_named_direct_route_of_store_typed_prefix :
  forall env s Σ p T,
    store_typed_prefix env s Σ ->
    typed_place_env_structural env Σ p T ->
    root_set_store_roots_named (root_of_place p) s.
Proof.
  intros env s Σ p T Hstore Htyped.
  eapply root_set_ctx_roots_named_store_typed_prefix.
  - exact Hstore.
  - eapply root_of_place_ctx_roots_named. exact Htyped.
Qed.

Lemma root_env_store_keys_named_update_env_direct_route :
  forall R s x roots,
    root_env_store_keys_named R s ->
    root_env_store_keys_named (root_env_update x roots R) s.
Proof.
  unfold root_env_store_keys_named.
  intros R s x roots Hkeys.
  apply root_env_keys_named_update. exact Hkeys.
Qed.

Lemma place_borrow_roots_store_roots_named_direct_route :
  forall R s p roots,
    root_env_store_roots_named R s ->
    root_set_store_roots_named (root_of_place p) s ->
    place_borrow_roots R p = Some roots ->
    root_set_store_roots_named roots s.
Proof.
  intros R s p roots Henv Hplace Hborrow.
  unfold place_borrow_roots in Hborrow.
  destruct (place_path p) as [[x path] |] eqn:Hpath.
  - inversion Hborrow; subst roots. exact Hplace.
  - assert (Hlookup :
      root_env_lookup (root_provenance_place_name p) R = Some roots).
    { rewrite <- (place_root_lookup_indirect R p Hpath). exact Hborrow. }
    eapply root_env_lookup_store_roots_named_direct_route; eassumption.
Qed.

Lemma resolve_root_set_fuel_store_roots_named_direct_route :
  forall fuel R s roots out,
    root_env_store_roots_named R s ->
    root_set_store_roots_named roots s ->
    resolve_root_set_fuel fuel R roots = Some out ->
    root_set_store_roots_named out s.
Proof.
  induction fuel as [| fuel IH]; intros R s roots out Henv Hroots Hres;
    simpl in Hres; try discriminate.
  destruct (singleton_store_root roots) as [x |] eqn:Hsingle.
  - destruct (root_env_lookup x R) as [env_roots |] eqn:Hlookup.
    + assert (Henv_roots : root_set_store_roots_named env_roots s)
        by (eapply root_env_lookup_store_roots_named_direct_route;
            eassumption).
      destruct (singleton_store_root env_roots) as [y |] eqn:Henv_single.
      * destruct (ident_eqb x y) eqn:Hxy.
        -- inversion Hres; subst out. exact Hroots.
        -- eapply IH; eassumption.
      * eapply IH; eassumption.
    + inversion Hres; subst out. exact Hroots.
  - inversion Hres; subst out. exact Hroots.
Qed.

Lemma place_resolved_roots_store_roots_named_direct_route :
  forall R s p roots,
    root_env_store_roots_named R s ->
    root_set_store_roots_named (root_of_place p) s ->
    place_resolved_roots R p = Some roots ->
    root_set_store_roots_named roots s.
Proof.
  intros R s p roots Henv Hplace Hresolved.
  unfold place_resolved_roots in Hresolved.
  destruct (place_borrow_roots R p) as [borrow_roots |] eqn:Hborrow;
    try discriminate.
  assert (Hborrow_named : root_set_store_roots_named borrow_roots s).
  { eapply place_borrow_roots_store_roots_named_direct_route; eassumption. }
  unfold resolve_root_set in Hresolved.
  eapply resolve_root_set_fuel_store_roots_named_direct_route; eassumption.
Qed.

Lemma typed_place_env_structural_store_typed_prefix_static_runtime_named_leaf :
  forall env s Σ R p T,
    store_typed_prefix env s Σ ->
    typed_place_env_structural env Σ p T ->
    root_env_store_roots_named R s ->
    root_set_store_roots_named (root_of_place p) s /\
    (forall roots,
      place_borrow_roots R p = Some roots ->
      root_set_store_roots_named roots s) /\
    (forall roots,
      place_resolved_roots R p = Some roots ->
      root_set_store_roots_named roots s).
Proof.
  intros env s Σ R p T Hstore Htyped Hnamed.
  assert (Hplace : root_set_store_roots_named (root_of_place p) s).
  { eapply root_of_place_store_roots_named_direct_route_of_store_typed_prefix;
      eassumption. }
  repeat split.
  - exact Hplace.
  - intros roots Hborrow.
    eapply place_borrow_roots_store_roots_named_direct_route; eassumption.
  - intros roots Hresolved.
    eapply place_resolved_roots_store_roots_named_direct_route; eassumption.
Qed.

Inductive preservation_ready_expr_static_runtime_named_leaf : expr -> Prop :=
  | PRSRN_Unit :
      preservation_ready_expr_static_runtime_named_leaf EUnit
  | PRSRN_Lit : forall lit,
      preservation_ready_expr_static_runtime_named_leaf (ELit lit)
  | PRSRN_Var : forall x,
      preservation_ready_expr_static_runtime_named_leaf (EVar x)
  | PRSRN_Fn : forall fname,
      preservation_ready_expr_static_runtime_named_leaf (EFn fname)
  | PRSRN_Place : forall p x path,
      place_path p = Some (x, path) ->
      preservation_ready_expr_static_runtime_named_leaf (EPlace p).

Lemma preservation_ready_expr_static_runtime_named_leaf_complete :
  forall env s e (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_expr_static_runtime_named_leaf e ->
    preservation_ready_expr e ->
    typed_env_roots env Ω n R Σ e T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros env s e Ω n R Σ T Σ' R' roots Hleaf Hready Htyped _ Hwithin
    Hnamed Hkeys.
  inversion Hleaf; subst; inversion Htyped; subst;
    repeat split; try assumption; try apply root_set_store_roots_named_nil;
    try (eapply root_env_lookup_store_roots_named_direct_route; eassumption).
Qed.

Lemma preservation_ready_borrow_static_runtime_named_store_typed_prefix :
  forall env s rk p (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_expr (EBorrow rk p) ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ (EBorrow rk p) T Σ' R' roots ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros env s rk p Ω n R Σ T Σ' R' roots Hready Hstore Htyped
    Hwithin Hnamed Hkeys.
  inversion Hready; subst; clear Hready.
  inversion Htyped; subst; try congruence; repeat split; try assumption.
  - match goal with
    | Htyped_place : typed_place_env_structural _ _ p _ |- _ =>
        destruct (typed_place_env_structural_store_typed_prefix_static_runtime_named_leaf
          _ _ _ _ _ _ Hstore Htyped_place Hnamed) as [Hplace _]
    end.
    exact Hplace.
  - assert (Hplace : root_set_store_roots_named (root_of_place p) s).
    { eapply root_of_place_store_roots_named_direct_route_of_store_typed_prefix;
        eassumption. }
    match goal with
    | Hpath : place_path p = Some (_, _) |- _ =>
        unfold root_of_place in Hplace; rewrite Hpath in Hplace; exact Hplace
    end.
Qed.

Lemma preservation_ready_borrow_static_runtime_named_prefix_instance :
  forall rk p env s (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_expr (EBorrow rk p) ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ (EBorrow rk p) T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros rk p env s Ω n R Σ T Σ' R' roots Hready Hstore Htyped _Hrn
    Hwithin Hnamed Hkeys.
  eapply preservation_ready_borrow_static_runtime_named_store_typed_prefix;
    eassumption.
Qed.

Inductive preservation_ready_expr_static_runtime_named_leaf_or_borrow : expr -> Prop :=
  | PRSRNB_Leaf : forall e,
      preservation_ready_expr_static_runtime_named_leaf e ->
      preservation_ready_expr_static_runtime_named_leaf_or_borrow e
  | PRSRNB_Borrow : forall rk p x path,
      place_path p = Some (x, path) ->
      preservation_ready_expr_static_runtime_named_leaf_or_borrow (EBorrow rk p).

Lemma preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_complete :
  forall env s e (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_expr_static_runtime_named_leaf_or_borrow e ->
    preservation_ready_expr e ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ e T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros env s e Ω n R Σ T Σ' R' roots Hcase Hready Hstore Htyped
    Hrn Hwithin Hnamed Hkeys.
  inversion Hcase; subst.
  - eapply preservation_ready_expr_static_runtime_named_leaf_complete;
      eassumption.
  - eapply preservation_ready_borrow_static_runtime_named_prefix_instance;
      eassumption.
Qed.

Lemma store_entries_typed_static_update_state_direct_route :
  forall env s entries Σ x f Σ',
    Forall2 (store_entry_typed env s) entries Σ ->
    (forall runtime static,
      binding_state_refines runtime static ->
      binding_state_refines runtime (f static)) ->
    sctx_update_state x f Σ = Some Σ' ->
    Forall2 (store_entry_typed env s) entries Σ'.
Proof.
  intros env s entries Σ x f Σ' Htyped Href Hupdate.
  revert Σ' Hupdate.
  induction Htyped as [| se ce entries_tail Σ_tail Hentry Htail IH];
    intros Σ' Hupdate.
  - simpl in Hupdate. discriminate.
  - destruct se as [sx sT sv sst].
    destruct ce as [[[cx cT] cst] cm].
    simpl in Hentry.
    destruct Hentry as [Hname [HT [Hst Hv]]].
    simpl in Hupdate.
    destruct (ident_eqb x cx) eqn:Hcx.
    + injection Hupdate as Hsame. subst Σ'.
      constructor.
      * simpl. repeat split; try assumption.
        apply Href. exact Hst.
      * exact Htail.
    + destruct (ctx_update_state x f Σ_tail) as [Σ_tail' |]
        eqn:Htail_update.
      * unfold sctx_update_state in Hupdate.
        rewrite Htail_update in Hupdate.
        injection Hupdate as Hsame. subst Σ'.
        constructor.
        -- simpl. repeat split; assumption.
        -- apply IH. unfold sctx_update_state. exact Htail_update.
      * unfold sctx_update_state in Hupdate.
        rewrite Htail_update in Hupdate.
        discriminate.
Qed.

Lemma store_typed_prefix_static_update_state_direct_route :
  forall env s Σ x f Σ',
    store_typed_prefix env s Σ ->
    (forall runtime static,
      binding_state_refines runtime static ->
      binding_state_refines runtime (f static)) ->
    sctx_update_state x f Σ = Some Σ' ->
    store_typed_prefix env s Σ'.
Proof.
  intros env s Σ x f Σ' Hstore Href Hupdate.
  unfold store_typed_prefix in Hstore.
  destruct Hstore as [entries [frame [Hs Hentries]]].
  unfold store_typed_prefix.
  exists entries, frame. split; [exact Hs |].
  eapply store_entries_typed_static_update_state_direct_route; eassumption.
Qed.

Lemma binding_state_refines_static_consume_path_direct_route :
  forall runtime static p,
    binding_state_refines runtime static ->
    binding_state_refines runtime (state_consume_path p static).
Proof.
  intros runtime [sconsumed smoved] p Href q Havailable.
  destruct p as [| seg rest].
  - simpl in Havailable.
    unfold binding_available_b in Havailable. simpl in Havailable.
    discriminate.
  - unfold binding_available_b in Havailable.
    simpl in Havailable.
    destruct sconsumed; simpl in Havailable; try discriminate.
    destruct (path_conflict_b q (seg :: rest)) eqn:Hconflict;
      simpl in Havailable; try discriminate.
    destruct (path_conflicts_any_b q smoved) eqn:Hstatic;
      simpl in Havailable; try discriminate.
    apply Href.
    unfold binding_available_b. simpl. rewrite Hstatic. reflexivity.
Qed.

Lemma store_typed_prefix_static_consume_path_direct_route :
  forall env s Σ x p Σ',
    store_typed_prefix env s Σ ->
    sctx_consume_path Σ x p = infer_ok Σ' ->
    store_typed_prefix env s Σ'.
Proof.
  intros env s Σ x p Σ' Hstore Hconsume.
  unfold sctx_consume_path, sctx_path_available in Hconsume.
  destruct (sctx_lookup x Σ) as [[T st] |] eqn:Hlookup; try discriminate.
  destruct (binding_available_b st p) eqn:Havailable; try discriminate.
  destruct (sctx_update_state x (state_consume_path p) Σ) as [Σ0 |]
    eqn:Hupdate; try discriminate.
  inversion Hconsume; subst Σ0.
  eapply store_typed_prefix_static_update_state_direct_route.
  - exact Hstore.
  - intros runtime static Href.
    apply binding_state_refines_static_consume_path_direct_route. exact Href.
  - exact Hupdate.
Qed.

Lemma root_env_store_roots_named_direct_route_store_names_eq :
  forall R s s',
    store_names s' = store_names s ->
    root_env_store_roots_named R s ->
    root_env_store_roots_named R s'.
Proof.
  unfold root_env_store_roots_named.
  intros R s s' Hnames Hnamed x roots z Hlookup Hin.
  rewrite Hnames. eapply Hnamed; eassumption.
Qed.

Lemma root_set_store_roots_named_direct_route_store_names_eq :
  forall roots s s',
    store_names s' = store_names s ->
    root_set_store_roots_named roots s ->
    root_set_store_roots_named roots s'.
Proof.
  unfold root_set_store_roots_named.
  intros roots s s' Hnames Hnamed z Hin.
  rewrite Hnames. eapply Hnamed; eassumption.
Qed.

Lemma root_env_store_keys_named_direct_route_store_names_eq :
  forall R s s',
    store_names s' = store_names s ->
    root_env_store_keys_named R s ->
    root_env_store_keys_named R s'.
Proof.
  unfold root_env_store_keys_named, root_env_keys_named.
  intros R s s' Hnames Hkeys x Hin.
  rewrite Hnames. eapply Hkeys; eassumption.
Qed.

Lemma store_typed_prefix_ctx_merge_many_left_direct_route :
  forall env s Σ tail Γ,
    store_typed_prefix env s Σ ->
    ctx_merge_many (ctx_of_sctx Σ) (map ctx_of_sctx tail) = Some Γ ->
    store_typed_prefix env s (sctx_of_ctx Γ).
Proof.
  intros env s Σ tail.
  revert Σ.
  induction tail as [| Σh rest IH]; intros Σ Γ Hstore Hmerge.
  - simpl in Hmerge. inversion Hmerge; subst. exact Hstore.
  - simpl in Hmerge.
    destruct (ctx_merge (ctx_of_sctx Σ) (ctx_of_sctx Σh)) as [Σm |]
      eqn:Hhead; try discriminate.
    eapply IH.
    + eapply store_typed_prefix_ctx_merge_left.
      * exact Hstore.
      * exact Hhead.
    + exact Hmerge.
Qed.

Lemma preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_store_typed_prefix :
  forall env s e (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_expr_static_runtime_named_leaf_or_borrow e ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ e T Σ' R' roots ->
    store_typed_prefix env s Σ'.
Proof.
  intros env s e Ω n R Σ T Σ' R' roots Hcase Hstore Htyped.
  inversion Hcase; subst.
  - inversion H; subst; inversion Htyped; subst; try exact Hstore;
      eapply store_typed_prefix_static_consume_path_direct_route; eassumption.
  - inversion Htyped; subst; exact Hstore.
Qed.

Lemma typed_args_roots_preservation_ready_static_runtime_named_prefix_leaf_or_borrow :
  preservation_ready_expr_static_runtime_named_prefix_statement ->
  forall env s args (Ω : outlives_ctx) (n : nat) R Σ ps Σ_args R_args
      arg_roots,
    preservation_ready_args args ->
    Forall preservation_ready_expr_static_runtime_named_leaf_or_borrow args ->
    store_typed_prefix env s Σ ->
    typed_args_roots env Ω n R Σ args ps Σ_args R_args arg_roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_typed_prefix env s Σ_args /\
    store_roots_within R_args s /\
    root_env_store_roots_named R_args s /\
    Forall (fun roots => root_set_store_roots_named roots s) arg_roots /\
    root_env_store_keys_named R_args s.
Proof.
  intros Hexpr env s args Ω n R Σ ps Σ_args R_args arg_roots Hready
    Hall Hstore Htyped Hrn Hwithin Hnamed Hkeys.
  revert Hready Hall Hstore Hrn Hwithin Hnamed Hkeys.
  induction Htyped as
    [R0 Σ0
    | R0 R1 R2 Σ0 Σ1 Σ2 e es p ps0 T_e roots roots_rest
        Htyped_e Hcompat Htyped_rest IH];
    intros Hready Hall Hstore Hrn Hwithin Hnamed Hkeys.
  - dependent destruction Hready.
    dependent destruction Hall.
    repeat split; try constructor; assumption.
  - dependent destruction Hready.
    dependent destruction Hall.
    assert (Hrn1 : root_env_no_shadow R1)
      by (eapply typed_env_roots_no_shadow; eassumption).
    destruct (Hexpr env s e Ω n R0 Σ0 T_e Σ1 R1 roots H Hstore
                Htyped_e Hrn Hwithin Hnamed Hkeys)
      as [Hwithin1 [Hnamed1 [Hroots_named Hkeys1]]].
    assert (Hstore1 : store_typed_prefix env s Σ1).
    { eapply preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_store_typed_prefix;
        eassumption. }
    destruct (IH Hready Hall Hstore1 Hrn1 Hwithin1 Hnamed1 Hkeys1)
      as [Hstore2 [Hwithin2 [Hnamed2 [Hroots_rest_named Hkeys2]]]].
    repeat split; try assumption.
    constructor; assumption.
Qed.

Lemma preservation_ready_fields_leaf_or_borrow_lookup_direct_route :
  forall fields name e,
    Forall (fun field =>
      preservation_ready_expr_static_runtime_named_leaf_or_borrow (snd field)) fields ->
    lookup_field_b name fields = Some e ->
    preservation_ready_expr_static_runtime_named_leaf_or_borrow e.
Proof.
  intros fields name e Hall Hlookup.
  unfold lookup_field_b in Hlookup.
  induction Hall as [| [fname field_expr] rest Hfield Hrest IH];
    simpl in Hlookup.
  - discriminate.
  - destruct (String.eqb name fname) eqn:Hname.
    + inversion Hlookup; subst. exact Hfield.
    + apply IH. exact Hlookup.
Qed.

Lemma preservation_ready_fields_lookup_direct_route :
  forall fields name e,
    preservation_ready_fields fields ->
    lookup_field_b name fields = Some e ->
    preservation_ready_expr e.
Proof.
  intros fields name e Hready Hlookup.
  rewrite lookup_field_b_lookup_expr_field in Hlookup.
  eapply preservation_ready_fields_lookup; eassumption.
Qed.

Lemma typed_fields_roots_preservation_ready_static_runtime_named_prefix_leaf_or_borrow :
  preservation_ready_expr_static_runtime_named_prefix_statement ->
  forall env s (Ω : outlives_ctx) (n : nat) lts args R Σ fields defs
      Σ_fields R_fields roots_fields,
    preservation_ready_fields fields ->
    Forall (fun field =>
      preservation_ready_expr_static_runtime_named_leaf_or_borrow (snd field)) fields ->
    store_typed_prefix env s Σ ->
    typed_fields_roots env Ω n lts args R Σ fields defs Σ_fields R_fields roots_fields ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_typed_prefix env s Σ_fields /\
    store_roots_within R_fields s /\
    root_env_store_roots_named R_fields s /\
    root_set_store_roots_named roots_fields s /\
    root_env_store_keys_named R_fields s.
Proof.
  intros Hexpr env s Ω n lts args R Σ fields defs Σ_fields R_fields
    roots_fields Hready Hall Hstore Htyped Hrn Hwithin Hnamed Hkeys.
  revert Hstore Hrn Hwithin Hnamed Hkeys.
  induction Htyped as
    [lts args R0 Σ0 fields0
    | lts args R0 R1 R2 Σ0 Σ1 Σ2 fields0 f rest e_field T_field
        roots_field roots_rest Hlookup Htyped_e Hcompat Htyped_rest IH];
    intros Hstore Hrn Hwithin Hnamed Hkeys.
  - repeat split; try apply root_set_store_roots_named_nil; assumption.
  - assert (Hready_e : preservation_ready_expr e_field).
    { eapply preservation_ready_fields_lookup_direct_route; eassumption. }
    assert (Hleaf_e :
      preservation_ready_expr_static_runtime_named_leaf_or_borrow e_field).
    { eapply preservation_ready_fields_leaf_or_borrow_lookup_direct_route;
        eassumption. }
    assert (Hrn1 : root_env_no_shadow R1)
      by (eapply typed_env_roots_no_shadow; eassumption).
    destruct (Hexpr env s e_field Ω n R0 Σ0 T_field Σ1 R1 roots_field
                Hready_e Hstore Htyped_e Hrn Hwithin Hnamed Hkeys)
      as [Hwithin1 [Hnamed1 [Hroots_field_named Hkeys1]]].
    assert (Hstore1 : store_typed_prefix env s Σ1).
    { eapply preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_store_typed_prefix;
        eassumption. }
    destruct (IH Hready Hall Hstore1 Hrn1 Hwithin1 Hnamed1 Hkeys1)
      as [Hstore2 [Hwithin2 [Hnamed2 [Hroots_rest_named Hkeys2]]]].
    repeat split; try assumption.
    apply root_set_store_roots_named_union; assumption.
Qed.

Lemma match_payload_params_empty_direct_route :
  forall lts args v ps,
    match_payload_params [] lts args v = infer_ok ps ->
    ps = [].
Proof.
  intros lts args v ps Hparams.
  unfold match_payload_params in Hparams.
  destruct (instantiate_enum_variant_field_tys lts args v) as [| T Ts];
    simpl in Hparams; try discriminate.
  inversion Hparams. reflexivity.
Qed.

Lemma preservation_ready_match_branches_lookup_direct_route :
  forall branches name e,
    preservation_ready_match_branches branches ->
    lookup_expr_branch name branches = Some e ->
    preservation_ready_expr e.
Proof.
  intros branches name e Hready Hlookup.
  induction Hready as [| name0 binders e0 rest Hbinders He0 Hrest IH];
    simpl in Hlookup.
  - discriminate.
  - destruct (String.eqb name name0) eqn:Hname.
    + inversion Hlookup; subst. exact He0.
    + apply IH. exact Hlookup.
Qed.

Lemma preservation_ready_match_branches_leaf_or_borrow_lookup_direct_route :
  forall branches name e,
    Forall (fun branch =>
      match branch with
      | (_, _, expr) =>
          preservation_ready_expr_static_runtime_named_leaf_or_borrow expr
      end) branches ->
    lookup_expr_branch name branches = Some e ->
    preservation_ready_expr_static_runtime_named_leaf_or_borrow e.
Proof.
  intros branches name e Hall Hlookup.
  induction Hall as [| [[name0 binders] e0] rest Hbranch Hrest IH];
    simpl in Hlookup.
  - discriminate.
  - destruct (String.eqb name name0) eqn:Hname.
    + inversion Hlookup; subst. exact Hbranch.
    + apply IH. exact Hlookup.
Qed.

Lemma typed_match_tail_roots_preservation_ready_static_runtime_named_prefix_leaf_or_borrow :
  preservation_ready_expr_static_runtime_named_prefix_statement ->
  forall env s (Ω : outlives_ctx) (n : nat) lts args R roots_scrut Σ
      branches variants expected_core R_out Σs Ts rootss,
    preservation_ready_match_branches branches ->
    Forall (fun branch =>
      match branch with
      | (_, _, expr) =>
          preservation_ready_expr_static_runtime_named_leaf_or_borrow expr
      end) branches ->
    store_typed_prefix env s Σ ->
    typed_match_tail_roots env Ω n lts args R roots_scrut Σ branches variants
      expected_core R_out Σs Ts rootss ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    Forall (store_typed_prefix env s) Σs /\
    Forall (fun roots => root_set_store_roots_named roots s) rootss.
Proof.
  intros Hexpr env s Ω n lts args R roots_scrut Σ branches variants
    expected_core R_out Σs Ts rootss Hready Hall Hstore Htyped Hrn Hwithin
    Hnamed Hkeys.
  revert Hstore Hrn Hwithin Hnamed Hkeys.
  induction Htyped as
    [lts args R0 roots_scrut Σ0 branches0 expected_core R_out
    | R0 R_payload Rv_payload Rv Σ0 branches0 v rest e T Σv_payload Σv
        R_out roots Σs Ts rootss expected_core binders ps lts args
        roots_scrut Hbinders Hparams Hnodup Hctx_none Hroot_none Hlookup
        HR_payload Htyped_e Hno_lbound Hparams_ok Hroots_excl HRv
        HRv_excl HΣv Hcore HRout Htyped_tail IH];
    intros Hstore Hrn Hwithin Hnamed Hkeys.
  - repeat constructor.
  - assert (Hbinders_empty : binders = []).
    { eapply lookup_expr_branch_binders_preservation_ready_empty;
        eassumption. }
    subst binders.
    assert (Hps_empty : ps = []).
    { eapply match_payload_params_empty_direct_route; eassumption. }
    subst ps.
    simpl in HR_payload. subst R_payload.
    simpl in Htyped_e.
    assert (Hready_e : preservation_ready_expr e).
    { eapply preservation_ready_match_branches_lookup_direct_route;
        eassumption. }
    assert (Hleaf_e :
      preservation_ready_expr_static_runtime_named_leaf_or_borrow e).
    { eapply preservation_ready_match_branches_leaf_or_borrow_lookup_direct_route;
        eassumption. }
    assert (Hrn_payload : root_env_no_shadow R0) by exact Hrn.
    destruct (Hexpr env s e Ω n R0 Σ0 T Σv_payload Rv_payload roots
                Hready_e Hstore Htyped_e Hrn_payload Hwithin Hnamed Hkeys)
      as [Hwithin_payload [Hnamed_payload [Hroots_named Hkeys_payload]]].
    assert (Hstore_payload : store_typed_prefix env s Σv_payload).
    { eapply preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_store_typed_prefix;
        eassumption. }
    simpl in HΣv. subst Σv.
    destruct (IH Hready Hall Hstore Hrn Hwithin Hnamed Hkeys)
      as [Hstores_tail Hroots_tail].
    split.
    + constructor; assumption.
    + constructor; assumption.
Qed.

Lemma preservation_ready_struct_static_runtime_named_prefix_leaf_or_borrow :
  preservation_ready_expr_static_runtime_named_prefix_statement ->
  forall env s sname lts args fields (Ω : outlives_ctx) (n : nat)
      R Σ T Σ' R' roots,
    preservation_ready_fields fields ->
    Forall (fun field =>
      preservation_ready_expr_static_runtime_named_leaf_or_borrow (snd field)) fields ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ (EStruct sname lts args fields) T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_typed_prefix env s Σ' /\
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros Hexpr env s sname lts args fields Ω n R Σ T Σ' R' roots
    Hready Hall Hstore Htyped Hrn Hwithin Hnamed Hkeys.
  inversion Htyped; subst.
  match goal with
  | Hfields : typed_fields_roots _ _ _ _ _ _ _ _ _ _ _ _ |- _ =>
      destruct (typed_fields_roots_preservation_ready_static_runtime_named_prefix_leaf_or_borrow
                  Hexpr env s Ω n lts args R Σ fields (struct_fields sdef)
                  Σ' R' roots Hready Hall Hstore Hfields Hrn Hwithin Hnamed Hkeys)
        as [Hstore' [Hwithin' [Hnamed' [Hroots_named Hkeys']]]]
  end.
  repeat split; assumption.
Qed.

Lemma preservation_ready_enum_static_runtime_named_prefix_leaf_or_borrow :
  preservation_ready_expr_static_runtime_named_prefix_statement ->
  forall env s enum_name variant_name lts variant_lts args payloads
      (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_args payloads ->
    Forall preservation_ready_expr_static_runtime_named_leaf_or_borrow payloads ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ
      (EEnum enum_name variant_name lts variant_lts args payloads)
      T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_typed_prefix env s Σ' /\
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros Hexpr env s enum_name variant_name lts variant_lts args payloads Ω n
    R Σ T Σ' R' roots Hready Hall Hstore Htyped Hrn Hwithin Hnamed Hkeys.
  inversion Htyped; subst.
  match goal with
  | Hargs : typed_args_roots _ _ _ _ _ payloads _ _ _ _ |- _ =>
      destruct (typed_args_roots_preservation_ready_static_runtime_named_prefix_leaf_or_borrow
                  Hexpr env s payloads Ω n R Σ
                  (params_of_tys
                    (map (instantiate_enum_variant_field_ty lts variant_lts args)
                      (enum_variant_fields vdef)))
                  Σ' R' payload_roots Hready Hall Hstore Hargs Hrn Hwithin
                  Hnamed Hkeys)
        as [Hstore' [Hwithin' [Hnamed' [Hpayloads_named Hkeys']]]]
  end.
  repeat split; try assumption.
  apply root_sets_union_store_roots_named. exact Hpayloads_named.
Qed.

Lemma preservation_ready_match_static_runtime_named_prefix_leaf_or_borrow :
  preservation_ready_expr_static_runtime_named_prefix_statement ->
  forall env s scrut branches (Ω : outlives_ctx) (n : nat) R Σ T Σ' R'
      roots,
    preservation_ready_expr scrut ->
    preservation_ready_match_branches branches ->
    preservation_ready_expr_static_runtime_named_leaf_or_borrow scrut ->
    Forall (fun branch =>
      match branch with
      | (_, _, expr) =>
          preservation_ready_expr_static_runtime_named_leaf_or_borrow expr
      end) branches ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ (EMatch scrut branches) T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_typed_prefix env s Σ' /\
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros Hexpr env s scrut branches Ω n R Σ T Σ' R' roots Hready_scrut
    Hready_branches Hleaf_scrut Hall Hstore Htyped Hrn Hwithin Hnamed Hkeys.
  inversion Htyped; subst.
  match goal with
  | Hscrut : typed_env_roots _ _ _ _ _ scrut _ _ _ _ |- _ =>
      destruct (Hexpr env s scrut Ω n R Σ T_scrut Σ1 R1 roots_scrut
                Hready_scrut Hstore Hscrut Hrn Hwithin Hnamed Hkeys)
        as [Hwithin1 [Hnamed1 [Hroots_scrut_named Hkeys1]]];
      assert (Hstore1 : store_typed_prefix env s Σ1) by
        (eapply preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_store_typed_prefix;
          eassumption);
      assert (Hrn1 : root_env_no_shadow R1) by
        (eapply typed_env_roots_no_shadow; eassumption)
  end.
  assert (Hbinders_head_empty : binders_head = []).
  { eapply lookup_expr_branch_binders_preservation_ready_empty; eassumption. }
  subst binders_head.
  assert (Hps_head_empty : ps_head = []).
  { eapply match_payload_params_empty_direct_route; eassumption. }
  subst ps_head.
  simpl in *.
  assert (Hready_head : preservation_ready_expr e_head).
  { eapply preservation_ready_match_branches_lookup_direct_route; eassumption. }
  assert (Hleaf_head :
    preservation_ready_expr_static_runtime_named_leaf_or_borrow e_head).
  { eapply preservation_ready_match_branches_leaf_or_borrow_lookup_direct_route;
      eassumption. }
  match goal with
  | Hhead : typed_env_roots _ _ _ _ _ e_head _ _ _ _ |- _ =>
      destruct (Hexpr env s e_head Ω n R1 Σ1 T_head Σ_head_payload
                R_head_payload roots_head Hready_head Hstore1 Hhead Hrn1 Hwithin1
                Hnamed1 Hkeys1)
        as [Hwithin_head [Hnamed_head [Hroots_head_named Hkeys_head]]];
      assert (Hstore_head : store_typed_prefix env s Σ_head_payload) by
        (eapply preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_store_typed_prefix;
          eassumption)
  end.
  match goal with
  | Htail : typed_match_tail_roots _ _ _ _ _ _ _ _ _ _ _ _ _ _ _ |- _ =>
      pose proof Htail as Htail_ready
  end.
  match goal with
  | Hmerge : ctx_merge_many (ctx_of_sctx _) _ = Some _ |- _ =>
      pose proof Hmerge as Hmerge_ready
  end.
  destruct (typed_match_tail_roots_preservation_ready_static_runtime_named_prefix_leaf_or_borrow
              Hexpr env s Ω n lts args R1 roots_scrut Σ1 branches v_tail
              (ty_core T_head) R_head_payload Σ_tail Ts_tail roots_tail
              Hready_branches Hall Hstore1 Htail_ready Hrn1 Hwithin1 Hnamed1 Hkeys1)
    as [Hstores_tail Hroots_tail].
  repeat split; try assumption.
  - eapply store_typed_prefix_ctx_merge_many_left_direct_route.
    + exact Hstore_head.
    + exact Hmerge_ready.
  - apply root_set_store_roots_named_union.
    + exact Hroots_head_named.
    + apply root_sets_union_store_roots_named. exact Hroots_tail.
Qed.

Lemma preservation_ready_if_static_runtime_named_prefix_leaf_or_borrow :
  preservation_ready_expr_static_runtime_named_prefix_statement ->
  forall env s e1 e2 e3 (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
    preservation_ready_expr e1 ->
    preservation_ready_expr e2 ->
    preservation_ready_expr e3 ->
    preservation_ready_expr_static_runtime_named_leaf_or_borrow e1 ->
    preservation_ready_expr_static_runtime_named_leaf_or_borrow e2 ->
    preservation_ready_expr_static_runtime_named_leaf_or_borrow e3 ->
    store_typed_prefix env s Σ ->
    typed_env_roots env Ω n R Σ (EIf e1 e2 e3) T Σ' R' roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_typed_prefix env s Σ' /\
    store_roots_within R' s /\
    root_env_store_roots_named R' s /\
    root_set_store_roots_named roots s /\
    root_env_store_keys_named R' s.
Proof.
  intros Hexpr env s e1 e2 e3 Ω n R Σ T Σ' R' roots Hready1 Hready2
    Hready3 Hleaf1 Hleaf2 Hleaf3 Hstore Htyped Hrn Hwithin Hnamed Hkeys.
  inversion Htyped; subst.
  destruct (Hexpr env s e1 Ω n R Σ T_cond Σ1 R1 roots_cond
              Hready1 Hstore H2 Hrn Hwithin Hnamed Hkeys)
    as [Hwithin1 [Hnamed1 [Hroots_cond_named Hkeys1]]].
  assert (Hstore1 : store_typed_prefix env s Σ1).
  { eapply preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_store_typed_prefix.
    - exact Hleaf1.
    - exact Hstore.
    - exact H2. }
  assert (Hrn1 : root_env_no_shadow R1) by
    (eapply typed_env_roots_no_shadow; eassumption).
  destruct (Hexpr env s e2 Ω n R1 Σ1 T2 Σ2 R' roots2
              Hready2 Hstore1 H4 Hrn1 Hwithin1 Hnamed1 Hkeys1)
    as [Hwithin2 [Hnamed2 [Hroots2_named Hkeys2]]].
  assert (Hstore2 : store_typed_prefix env s Σ2).
  { eapply preservation_ready_expr_static_runtime_named_prefix_leaf_or_borrow_store_typed_prefix.
    - exact Hleaf2.
    - exact Hstore1.
    - exact H4. }
  destruct (Hexpr env s e3 Ω n R1 Σ1 T3 Σ3 R3 roots3
              Hready3 Hstore1 H5 Hrn1 Hwithin1 Hnamed1 Hkeys1)
    as [_ [_ [Hroots3_named _]]].
  repeat split.
  - eapply store_typed_prefix_ctx_merge_left.
    + exact Hstore2.
    + exact H13.
  - exact Hwithin2.
  - exact Hnamed2.
  - apply root_set_store_roots_named_union; assumption.
  - exact Hkeys2.
Qed.

Lemma typed_args_roots_preservation_ready_static_runtime_named :
  preservation_ready_expr_static_runtime_named_statement ->
  forall env s args (Ω : outlives_ctx) (n : nat) R Σ ps Σ_args R_args
      arg_roots,
    preservation_ready_args args ->
    typed_args_roots env Ω n R Σ args ps Σ_args R_args arg_roots ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    store_roots_within R_args s /\
    root_env_store_roots_named R_args s /\
    Forall (fun roots => root_set_store_roots_named roots s) arg_roots /\
    root_env_store_keys_named R_args s.
Proof.
  intros Hexpr env s args Ω n R Σ ps Σ_args R_args arg_roots Hready
    Htyped Hrn Hwithin Hnamed Hkeys.
  revert Hready Hrn Hwithin Hnamed Hkeys.
  induction Htyped as
    [R0 Σ0
    | R0 R1 R2 Σ0 Σ1 Σ2 e es p ps0 T_e roots roots_rest
        Htyped_e Hcompat Htyped_rest IH];
    intros Hready Hrn Hwithin Hnamed Hkeys.
  - dependent destruction Hready.
    repeat split; try constructor; assumption.
  - dependent destruction Hready.
    assert (Hrn1 : root_env_no_shadow R1)
      by (eapply typed_env_roots_no_shadow; eassumption).
    destruct (Hexpr env s e Ω n R0 Σ0 T_e Σ1 R1 roots H
                Htyped_e Hrn Hwithin Hnamed Hkeys)
      as [Hwithin1 [Hnamed1 [Hroots_named Hkeys1]]].
    destruct (IH Hready Hrn1 Hwithin1 Hnamed1 Hkeys1)
      as [Hwithin2 [Hnamed2 [Hroots_rest_named Hkeys2]]].
    repeat split; try assumption.
    constructor; assumption.
Qed.

Lemma eval_args_preserves_root_names_keys_preservation_ready_runtime_with_static_expr :
  preservation_ready_expr_static_runtime_named_statement ->
  forall env s args s_args vs Ω n R Σ ps Σ_args R_args arg_roots,
    eval_args env s args s_args vs ->
    preservation_ready_args args ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    typed_args_roots env Ω n R Σ args ps Σ_args R_args arg_roots ->
    root_env_store_roots_named R_args s_args /\
    Forall (fun roots => root_set_store_roots_named roots s_args) arg_roots /\
    root_env_store_keys_named R_args s_args.
Proof.
  intros Hexpr env s args s_args vs Ω n R Σ ps Σ_args R_args arg_roots
    Heval_args Hready Hrn Hwithin Hnamed Hkeys Htyped.
  pose proof (proj1 (proj2 preservation_ready_eval_store_names_mutual)
                env s args s_args vs Heval_args Hready) as Hnames.
  destruct (typed_args_roots_preservation_ready_static_runtime_named
              Hexpr env s args Ω n R Σ ps Σ_args R_args arg_roots
              Hready Htyped Hrn Hwithin Hnamed Hkeys)
    as [_ [Hnamed_args [Hroots_named Hkeys_args]]].
  repeat split.
  - eapply root_env_store_roots_named_direct_route_store_names_eq;
      eassumption.
  - eapply Forall_impl; [| exact Hroots_named].
    intros roots Hroot_named.
    eapply root_set_store_roots_named_direct_route_store_names_eq;
      eassumption.
  - eapply root_env_store_keys_named_direct_route_store_names_eq;
      eassumption.
Qed.

Lemma eval_args_preserves_root_names_keys_preservation_ready_runtime_with_static_expr_prefix :
  eval_preserves_typing_ready_prefix_mutual_statement ->
  eval_preserves_roots_ready_mutual_statement ->
  preservation_ready_expr_static_runtime_named_prefix_statement ->
  forall env s args s_args vs Ω n R Σ ps Σ_args R_args arg_roots,
    eval_args env s args s_args vs ->
    preservation_ready_args args ->
    store_typed_prefix env s Σ ->
    root_env_no_shadow R ->
    store_roots_within R s ->
    store_no_shadow s ->
    root_env_store_roots_named R s ->
    root_env_store_keys_named R s ->
    typed_args_roots env Ω n R Σ args ps Σ_args R_args arg_roots ->
    root_env_store_roots_named R_args s_args /\
    Forall (fun roots => root_set_store_roots_named roots s_args) arg_roots /\
    root_env_store_keys_named R_args s_args.
Proof.
  intros Htyping_prefix Hroots_ready Hexpr env s args s_args vs Ω n R Σ ps
    Σ_args R_args arg_roots Heval_args Hready Hstore Hrn Hwithin Hshadow
    Hnamed Hkeys Htyped.
  revert s s_args vs Heval_args Hready Hstore Hrn Hwithin Hshadow Hnamed Hkeys.
  induction Htyped as
    [R0 Σ0
    | R0 R1 R2 Σ0 Σ1 Σ2 e es p ps0 T_e roots roots_rest
        Htyped_e Hcompat Htyped_rest IH];
    intros s s_args vs Heval_args Hready Hstore Hrn Hwithin Hshadow Hnamed Hkeys.
  - dependent destruction Heval_args.
    dependent destruction Hready.
    repeat split; try constructor; assumption.
  - dependent destruction Heval_args.
    dependent destruction Hready.
    pose proof (proj1 preservation_ready_eval_store_names_mutual
                  env s e s1 v H H0) as Hnames_e.
    destruct (Hexpr env s e Ω n R0 Σ0 T_e Σ1 R1 roots H0 Hstore
                Htyped_e Hrn Hwithin Hnamed Hkeys)
      as [_Hwithin1_s [Hnamed1_s [Hroots_named_s Hkeys1_s]]].
    destruct (proj1 Htyping_prefix env s e s1 v H Ω n Σ0 T_e Σ1 H0
                Hstore (typed_env_roots_structural env Ω n R0 Σ0 e T_e Σ1
                  R1 roots Htyped_e))
      as [Hstore1 [_ _]].
    destruct (proj1 Hroots_ready env s e s1 v H Ω n R0 Σ0 T_e Σ1 R1
                roots (preservation_ready_expr_implies_provenance_ready_direct_call
                  e H0) Hwithin Hshadow Hrn Htyped_e)
      as [Hwithin1 [_ [Hshadow1 Hrn1]]].
    assert (Hnamed1 : root_env_store_roots_named R1 s1).
    { eapply root_env_store_roots_named_direct_route_store_names_eq;
        eassumption. }
    assert (Hkeys1 : root_env_store_keys_named R1 s1).
    { eapply root_env_store_keys_named_direct_route_store_names_eq;
        eassumption. }
    match goal with
    | Heval_tail : eval_args env s1 es s2 vs |- _ =>
        pose proof (proj1 (proj2 preservation_ready_eval_store_names_mutual)
          env s1 es s2 vs Heval_tail Hready) as Hnames_tail;
        assert (Hroots_named_s1 : root_set_store_roots_named roots s1)
        by (eapply root_set_store_roots_named_direct_route_store_names_eq;
            eassumption);
        assert (Hroots_named_args : root_set_store_roots_named roots s2)
        by (eapply root_set_store_roots_named_direct_route_store_names_eq;
            eassumption);
        destruct (IH s1 s2 vs Heval_tail Hready Hstore1 Hrn1 Hwithin1
                    Hshadow1 Hnamed1 Hkeys1)
          as [Hnamed_args [Hroots_rest_named Hkeys_args]]
    end.
    repeat split; try assumption.
    constructor; assumption.
Qed.

Lemma eval_preserves_typing_roots_synthetic_direct_call_ready_prefix_statement_of_call_statement :
  eval_preserves_typing_roots_ready_prefix_mutual_statement ->
  eval_preserves_typing_roots_synthetic_direct_call_ready_prefix_call_statement ->
  eval_preserves_typing_roots_synthetic_direct_call_ready_prefix_statement.
Proof.
  intros Hprefix_ready Hcall env s e s' v Heval Ω n R Σ T Σ' R' roots
    Hready Hstore Hroots Hshadow Hrn Hnamed Hkeys Htyped Hunique Hevidence.
  inversion Hready as [e_ready Hpres_ready | fname args Hready_args]; subst.
  - pose proof
      (preservation_ready_expr_implies_provenance_ready_direct_call
        e Hpres_ready) as Hprov.
    exact (proj1 Hprefix_ready env s e s' v Heval Ω n R Σ T Σ' R'
      roots Hprov Hstore Hroots Hshadow Hrn Htyped).
  - eapply Hcall; eassumption.
Qed.

Lemma eval_preserves_frame_param_scope_synthetic_direct_call_ready_statement_of_call_statement :
  eval_preserves_frame_scope_roots_ready_mutual_statement ->
  eval_preserves_param_scope_roots_ready_mutual_statement ->
  eval_preserves_frame_param_scope_synthetic_direct_call_ready_call_statement ->
  eval_preserves_frame_param_scope_synthetic_direct_call_ready_statement.
Proof.
  intros Hframe_ready Hparam_ready Hcall env s e s' v Heval Ω n R Σ T Σ'
    R' roots ps frame Hready Htyped Hcover Hroots Hshadow Hrn Hframe Hfresh
    Hparam.
  inversion Hready as [e_ready Hpres_ready | fname args Hready_args]; subst.
  - pose proof
      (preservation_ready_expr_implies_provenance_ready_direct_call
        e Hpres_ready) as Hprov.
    destruct (proj1 Hframe_ready env s e s' v Heval Ω n R Σ T Σ' R'
      roots ps frame Hprov Htyped Hcover Hroots Hshadow Hrn Hframe Hfresh)
      as [_ [_ [_ [_ [Hframe' _]]]]].
    destruct (proj1 Hparam_ready env s e s' v Heval Ω n R Σ T Σ' R'
      roots ps frame Hprov Htyped Hcover Hparam) as [frame' Hparam'].
    split; [exact Hframe' | exists frame'; exact Hparam'].
  - eapply Hcall; eassumption.
Qed.

Lemma eval_preserves_frame_param_scope_synthetic_direct_call_ready_call_statement_of_statement :
  eval_preserves_frame_param_scope_synthetic_direct_call_ready_statement ->
  eval_preserves_frame_param_scope_synthetic_direct_call_ready_call_statement.
Proof.
  intros Hscope env s fname args s' v Heval Ω n R Σ T Σ' R' roots ps
    frame Hready_args Htyped Hcover Hroots Hshadow Hrn Hframe Hfresh
    Hparam.
  eapply Hscope; try eassumption.
  apply PDCR_Call. exact Hready_args.
Qed.

Theorem eval_preserves_frame_param_scope_synthetic_direct_call_ready_statement_iff_call_statement :
  eval_preserves_frame_scope_roots_ready_mutual_statement ->
  eval_preserves_param_scope_roots_ready_mutual_statement ->
  (eval_preserves_frame_param_scope_synthetic_direct_call_ready_statement <->
   eval_preserves_frame_param_scope_synthetic_direct_call_ready_call_statement).
Proof.
  intros Hframe_ready Hparam_ready.
  split.
  - apply
      eval_preserves_frame_param_scope_synthetic_direct_call_ready_call_statement_of_statement.
  - apply
      eval_preserves_frame_param_scope_synthetic_direct_call_ready_statement_of_call_statement;
      assumption.
Qed.


Theorem eval_preserves_typing_direct_call_roots_ready_without_env_ready_with_preservation_core :
  eval_preserves_typing_roots_ready_mutual_statement ->
  eval_preserves_typing_ready_mutual_statement ->
  eval_preserves_roots_ready_mutual_statement ->
  eval_preserves_frame_scope_roots_ready_mutual_statement ->
  eval_preserves_typing_roots_ready_prefix_mutual_package_statement ->
  eval_preserves_param_scope_roots_ready_mutual_statement ->
  forall env s e s' v,
    eval env s e s' v ->
    forall (Ω : outlives_ctx) (n : nat) R Σ T Σ' R' roots,
      preservation_direct_call_ready_expr e ->
      store_typed env s Σ ->
      store_roots_within R s ->
      store_no_shadow s ->
      root_env_no_shadow R ->
      root_env_store_roots_named R s ->
      root_env_store_keys_named R s ->
      typed_env_roots env Ω n R Σ e T Σ' R' roots ->
      fn_env_unique_by_name env ->
      direct_call_callee_body_root_evidence env ->
      store_typed env s' Σ' /\
      value_has_type env s' v T /\
      store_ref_targets_preserved env s s'.
Proof.
  intros Htyping_roots Htyping_ready Hroots_ready Hframe_scope_ready
    Htyping_roots_prefix_ready Hparam_scope_ready env s e s' v Heval Ω n R
    Σ T Σ' R' roots Hready Hstore Hroots Hshadow Hrn Hnamed Hkeys Htyped
    Hunique Hcallee_roots.
  inversion Hready as [e_ready Hpres_ready | fname args Hready_args]; subst.
  - pose proof
      (preservation_ready_expr_implies_provenance_ready_direct_call
        e Hpres_ready) as Hprov.
    destruct (proj1 Htyping_roots
                env s e s' v Heval Ω n R Σ T Σ' R' roots
                Hprov Hstore Hroots Hshadow Hrn Htyped)
      as [Hstore' [Hv [Hpres _]]].
    repeat split; assumption.
  - dependent destruction Heval.
    dependent destruction Htyped.
    try solve
      [ eapply
          (eval_direct_call_body_provenance_ready_preserves_typing_with_preservation_core
            Htyping_ready Hroots_ready Hframe_scope_ready
            Htyping_roots_prefix_ready
            Hparam_scope_ready);
        eauto ].
    match goal with
    | Hready_args0 : preservation_ready_args ?args_call |- _ =>
        pose proof (preservation_ready_args_implies_provenance_ready_closure
                      args_call Hready_args0) as Hprov_args
    end.
    repeat match goal with
    | Hlookup : lookup_fn (fn_name ?f_typed) (env_fns env) =
        Some ?f_runtime,
      Hin : In ?f_typed (env_fns env) |- _ =>
        pose proof (lookup_fn_unique_by_name env (fn_name f_typed)
          f_runtime f_typed Hlookup Hin eq_refl Hunique) as Hsame;
        subst f_runtime
    | Hlookup : lookup_fn ?fname_call (env_fns env) = Some ?f_runtime,
      Hin : In ?f_typed (env_fns env),
      Hname : fn_name ?f_typed = ?fname_call |- _ =>
        pose proof (lookup_fn_unique_by_name env fname_call f_runtime f_typed
          Hlookup Hin Hname Hunique) as Hsame;
        subst f_typed
    | Hlookup : lookup_fn ?fname_call (env_fns env) = Some ?f_runtime,
      Hin : In ?f_typed (env_fns env),
      Hname : ?fname_call = fn_name ?f_typed |- _ =>
        pose proof (lookup_fn_unique_by_name env fname_call f_runtime f_typed
          Hlookup Hin (eq_sym Hname) Hunique) as Hsame;
        subst f_typed
    end.
    match goal with
    | Htyped_args : typed_args_roots ?env_call ?Ω_call ?n_call ?R_call ?Σ_call ?args_call
        ?params_inst ?Σ_args_call ?R_args_call ?arg_roots,
      Heval_args : eval_args ?env_call ?s_call ?args_call ?s_args ?vs,
      Hrename : alpha_rename_fn_def (store_names ?s_args) ?fdef =
        (?fcall, ?used'),
      Hin : In ?fdef (env_fns ?env_call),
      Hcaps : fn_captures ?fdef = [] |- _ =>
        pose proof (Hcallee_roots Ω_call n_call R_call Σ_call
                      Σ_args_call R_args_call arg_roots
                      (fn_name fdef) args_call fdef fcall σ s s_args vs
                      used' Hin eq_refl Hcaps Htyped_args Heval_args Hprov_args
                      Hstore Hroots Hshadow Hrn Hnamed Hkeys Hrename)
          as Hbody_ready;
        pose proof
          (callee_body_root_provenance_ready_at_of_ready_at env fcall
            (call_param_root_env (fn_params fcall) arg_roots R_args_call)
            Hbody_ready) as Hbody_prov_ready;
        eapply
          (eval_direct_call_body_provenance_ready_preserves_typing_with_preservation_core
            Htyping_ready Hroots_ready Hframe_scope_ready
            Htyping_roots_prefix_ready
            Hparam_scope_ready);
          eassumption
    | Htyped_args : typed_args_roots env Ω n R Σ ?args_call
        (apply_lt_params ?σ (fn_params ?fdef)) Σ' R' ?arg_roots,
      Heval_args : eval_args env s ?args_call ?s_args ?vs,
      Hrename : alpha_rename_fn_def (store_names ?s_args) ?fdef =
        (?fcall, ?used'),
      Hin : In ?fdef (env_fns env),
      Hfname : fn_name ?fdef = ?fname_call,
      Hcaps : fn_captures ?fdef = [] |- _ =>
        pose proof (Hcallee_roots Ω n R Σ Σ' R' arg_roots
                      fname_call args_call fdef fcall σ s s_args vs
                      used' Hin Hfname Hcaps Htyped_args Heval_args Hprov_args
                      Hstore Hroots Hshadow Hrn Hnamed Hkeys Hrename)
          as Hbody_ready;
        pose proof
          (callee_body_root_provenance_ready_at_of_ready_at env fcall
            (call_param_root_env (fn_params fcall) arg_roots R')
            Hbody_ready) as Hbody_prov_ready;
        eapply
          (eval_direct_call_body_provenance_ready_preserves_typing_with_preservation_core
            Htyping_ready Hroots_ready Hframe_scope_ready
            Htyping_roots_prefix_ready
            Hparam_scope_ready);
          eassumption
    | Htyped_args : typed_args_roots env Ω n R Σ ?args_call
        (apply_lt_params ?σ (fn_params ?fdef)) Σ' R' ?arg_roots,
      Heval_args : eval_args env s ?args_call ?s_args ?vs,
      Hrename : alpha_rename_fn_def (store_names ?s_args) ?fdef =
        (?fcall, ?used'),
      Hin : In ?fdef (env_fns env),
      Hcaps : fn_captures ?fdef = [] |- _ =>
        pose proof (Hcallee_roots Ω n R Σ Σ' R' arg_roots
                      (fn_name fdef) args_call fdef fcall σ s s_args vs
                      used' Hin eq_refl Hcaps Htyped_args Heval_args Hprov_args
                      Hstore Hroots Hshadow Hrn Hnamed Hkeys Hrename)
          as Hbody_ready;
        pose proof
          (callee_body_root_provenance_ready_at_of_ready_at env fcall
            (call_param_root_env (fn_params fcall) arg_roots R')
            Hbody_ready) as Hbody_prov_ready;
        eapply
          (eval_direct_call_body_provenance_ready_preserves_typing_with_preservation_core
            Htyping_ready Hroots_ready Hframe_scope_ready
            Htyping_roots_prefix_ready
            Hparam_scope_ready);
          eassumption
    | _ =>
        eapply
          (eval_direct_call_body_provenance_ready_preserves_typing_with_preservation_core
            Htyping_ready Hroots_ready Hframe_scope_ready
            Htyping_roots_prefix_ready
            Hparam_scope_ready);
          eauto
    end; eauto.
Qed.

